func:
// ╔════════════════════════════════════════════════════════════╗
// ║  KONFIGUROVATELNÉ PARAMETRY - UPRAV HODNOTY N֦E           ║
// ╚════════════════════════════════════════════════════════════╝

const CONFIG = {
    // === TEPLOTY (°C) ===
    TEPLOTA_MAX: 69,        // Maximální teplota bojleru
    TEPLOTA_VYSOKA: 60,     // Vysoká teplota (bاný ohřev)
    TEPLOTA_STREDNI: 58,    // Střední teplota (levná elektřina)
    TEPLOTA_MIN: 20,        // Minimální teplota (vypnuto)
    TEPLOTA_POVINNY_SOLAR: 40, // Teplota v povinných hodinách když zítra velký solár

    // === HYSTEREZE A SPOTŘEBA ===
    HYSTEREZE: 500,         // Hystereze v W (zabraňuje oscilaci)
    SPOTREBA_BOJLER: 2500,  // Spotřeba bojleru v W

    // === CENOVÉ PRAHY ===
    PRICE_LEVEL_LEVNY: 6,   // Level ceny (1-24), kdy je proud levný
    CENA_KWH_LEVNA: 2.6,    // Cena v Kč/kWh, kdy je proud levný

    // === FORECAST ===
    FORECAST_THRESHOLD: 35000  // Práh forecastu v Wh (35kWh)
};

// ╔════════════════════════════════════════════════════════════╗
// ║  ULOŽENÍ DO FLOW PROMĚNNÝCH - NEMĚNIT                      ║
// ╚════════════════════════════════════════════════════════════╝

for (const [key, value] of Object.entries(CONFIG)) {
    flow.set(key, value);
}

msg.payload = {
    status: "Konfigurace uložena",
    config: CONFIG
};

node.status({fill: "green", shape: "dot", text: "Konfigurace uložena"});
//node.warn("Bojler konfigurace uložena: " + JSON.stringify(CONFIG));

return msg;

// 🧠 Rozhodovací logika bojleru — cílová teplota dle přebytku, ceny, forecastu
var TM=flow.get("TEPLOTA_MAX")||69,TV=flow.get("TEPLOTA_VYSOKA")||60,TS=flow.get("TEPLOTA_STREDNI")||55;
var TMI=flow.get("TEPLOTA_MIN")||20,TPS=flow.get("TEPLOTA_POVINNY_SOLAR")||40;
var HY=flow.get("HYSTEREZE")||500,SB=flow.get("SPOTREBA_BOJLER")||2500;
var PLV=flow.get("PRICE_LEVEL_LEVNY")||3,CKL=flow.get("CENA_KWH_LEVNA")||2.6;
var FT=flow.get("FORECAST_THRESHOLD")||35000;
var mxS=global.get("max_spotreba_sit")||24000,fD=global.get("forecast_vyroba_dnes")||0,fZ=global.get("forecast_vyroba_zitra")||0;
var cerp=global.get("cerpadlo_topi")===true;
var clE=global.get("homeassistant.homeAssistant.states['climate.smart_socket_thermostat_24090276694597600801c4e7ae0a2e53']")||{};
var aktT=parseFloat((clE.attributes||{}).temperature)||0;
var cfg=global.get("fve_config")||{},MG=cfg.max_spotreba_sit_w||22000,SM=cfg.safety_margin_w||2000,SL=MG-SM;
var dom=msg.jsme_doma==="on",rv=msg.rychle_voda==="on",tB=msg.teplota_bojleru||0;
var sBA=msg.spotreba_bojleru||0,bat=msg.battery_percent||0,rV=msg.rozdil_vyroby||0;
var let2=msg.letni_rezim==="on",aH=msg.auto_hlad==="on",aA=msg.auto_automatizace==="on";
var pL=msg.price_level||24,cK=msg.cena_kwh||10,cS=msg.celkova_spotreba||0,sSit=msg.spotreba_ze_site||0;
var hr=new Date().getHours(),mn=new Date().getMinutes(),cm=hr*60+mn;
var jPC=cm>=17*60&&cm<=19*60+30,bO=sBA>100,vK=SL-cS,mZ=bO||(vK>=SB);
var PZM=4000+SB+HY,PVM=4000,PZV=SB+HY,PVV=-HY;
var jLE=(pL<=PLV)||(cK<=CKL),sD=fD>FT,sDZ=fZ>FT;
var cT=TMI,dv="";
if(!dom){cT=TMI;dv="Není doma";}
else if(rv){cT=TM;dv="Rychle voda";}
else if(jPC&&tB<58){if(!mZ){cT=TMI;dv="Pov.čas limit sítě";}
else if(sDZ&&tB>=TPS){cT=TPS;dv="Pov.čas zítra sol→"+TPS+"°C";}
else if(sDZ){cT=TPS;dv="Pov.ohřev na "+TPS+"°C";}
else{cT=TV;dv="Pov.ohřev 17-19:30";}}
else if(cerp&&rV<PZV){cT=TMI;dv="NIBE přeb:"+Math.round(rV/1000)+"kW";}
else if(bat>96){var pM=bO?PVM:PZM,pV=bO?PVV:PZV;
if(rV>pM){cT=aH&&aA?TV:TM;dv=(aH?"Přeb+auto":"Bat plné+přeb ")+(Math.round(rV/1000))+"kW";}
else if(rV>pV){cT=TV;dv="Přeb "+Math.round(rV/1000)+"kW";}
else if(bO&&rV>-SB){cT=flow.get("posledni_cilova_teplota")||TMI;dv="Hystereze "+cT+"°C";}
else{if(!let2&&jLE&&mZ){cT=TS;dv="Levná L"+pL;}else{cT=TMI;dv=let2?"Léto čeká":"Drahá/málo";}}}
else{var p5=bO?PVV:PZV,pM5=bO?PVM:PZM;
if(rV>pM5){cT=TM;dv="Velký přeb "+Math.round(rV/1000)+"kW bat:"+bat+"%";}
else if(rV>p5){cT=TV;dv="Přeb "+Math.round(rV/1000)+"kW bat:"+bat+"%";}
else if(bO&&rV>-SB){cT=flow.get("posledni_cilova_teplota")||TMI;dv="Hystereze "+cT+"°C";}
else if(let2&&sD){cT=TMI;dv="Léto fc:"+Math.round(fD/1000)+"kWh";}
else if(!let2&&jLE&&mZ){cT=TS;dv="Levná L"+pL+" "+cK+"Kč";}
else{cT=TMI;dv=let2?"Léto solar":!mZ?"Limit sítě":"Drahá";}}
flow.set("posledni_cilova_teplota",cT);
var clSt=(clE||{}).state||"unavailable";
if(clSt==="unavailable"){node.status({fill:"red",shape:"ring",text:"Meross UNAVAIL"});return null;}
if(cT===aktT){node.status({fill:"blue",shape:"dot",text:cT+"/"+aktT+"°C BEZ ZMĚNY "+dv});return null;}
msg.payload={teplota:cT,duvod:dv,debug:{dom:dom,rv:rv,tB:tB,bat:bat,rV:rV,let2:let2,pL:pL,cK:cK,jLE:jLE,cS:cS,mZ:mZ}};
var b="grey";if(cT>=TV)b="green";else if(cT>=TS)b="yellow";
node.status({fill:b,shape:bO?"ring":"dot",text:cT+"°C "+dv});
return msg;

// Filtrace bazénu v3b — optimalizace pro solární přebytek
// ZIMA: min 1h/den, LÉTO: min 2h/den (bazén > 10°C)
// Léto + bazén ≤ 10°C: žádné povinné minimum (jen solar surplus)
// Žádný hard cutoff — deadline jen spouští urgentní režim

// === Konfigurace z fve_config ===
var cfg = global.get("fve_config") || {};
var S_ON  = cfg.filtrace_surplus_on_w  || 2500;
var S_OFF = cfg.filtrace_surplus_off_w || 1500;
var MIN_W = cfg.filtrace_min_zima_min  || 60;
var MIN_S = cfg.filtrace_min_leto_min  || 120;
var T_MIN = cfg.filtrace_pool_temp_min || 10;
var T_FREEZE = cfg.filtrace_min_pool_temp || 2;
var DEAD  = cfg.filtrace_deadline_h    || 23;
var ANTI  = (cfg.filtrace_anti_cycle_min || 10) * 60 * 1000;
var SOC_LOW  = cfg.filtrace_soc_low      || 40;
var SOLAR_OK = cfg.filtrace_solar_ok_kwh || 10;
var MIN_RUN_M = cfg.filtrace_min_run_min || 15;
var TICK = 2;

// === Vstupní data z msg ===
var fOn = msg.filtraceState === "on";
var letni = msg.letniRezim === "on";
var surplus = parseFloat(msg.solarSurplus) || 0;
var soc = parseFloat(msg.batterySoc) || 0;

// NIBE kompresor aktivní → filtrace pauza (nižší priorita než NIBE)
var nibeCompE = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var nibeComp = nibeCompE.state === "on";

// Teplota bazénu z HA
var tE = global.get("homeassistant.homeAssistant.states['sensor.hp2551ae_pro_v2_1_0_temperature_1']") || {};
var poolT = parseFloat(tE.state);
if (isNaN(poolT)) poolT = 0;

// FVE plán
var planData = global.get("fve_plan") || {};
var plan = planData.plan || [];
var cur = plan.length > 0 ? plan[0] : {};
var mode = cur.mode || "setrit";
var pLvl = cur.priceLevel || 0;

// Solární předpověď — zbývající dnes
var remE = global.get("homeassistant.homeAssistant.states['sensor.energy_production_today_remaining_3']") || {};
var solRemain = parseFloat(remE.state) || 0;

// === Čas ===
var d = new Date();
var tp = d.toLocaleTimeString("en-GB", {timeZone: "Europe/Prague", hour12: false}).split(":");
var hr = parseInt(tp[0]), mn = parseInt(tp[1]);
var nowM = hr * 60 + mn;
var now = d.getTime();

// === Denní tracker ===
var today = d.toLocaleDateString("en-CA", {timeZone: "Europe/Prague"});
var sDate = flow.get("filt_date") || "";
var run = flow.get("filt_run") || 0;
var newDay = today !== sDate;

var isRestart = sDate === "";
if (isRestart) {
    // NR restart — load counter from HA global (survives NR restart)
    var _saved = {};
    try { var _fs = global.get("fs"); _saved = JSON.parse(_fs.readFileSync("/config/filt_persist.json", "utf8")); } catch(e) {}
    if (_saved.date === today) { run = _saved.run || 0; }
    else if (hr >= 12) { run = minReq > 0 ? minReq : 60; }
    flow.set("filt_date", today);
    flow.set("filt_run", run);
} else if (newDay) {
    run = 0;
    flow.set("filt_date", today);
    flow.set("filt_run", 0);
}
if (fOn) {
    run += TICK;
    flow.set("filt_run", run);
}
// Persist counter via HA global (survives NR restart)
try { var _fs = global.get("fs"); _fs.writeFileSync("/config/filt_persist.json", JSON.stringify({date: today, run: run}), "utf8"); } catch(e) {}

// Min continuous run tracking (zákon 10.1)
var contStart = flow.get("filt_cont_start") || 0;
if (fOn && !(flow.get("filt_was_on"))) { contStart = now; flow.set("filt_cont_start", now); }
flow.set("filt_was_on", fOn);
var contRunMin = fOn ? (now - contStart) / 60000 : 0;
var minRunOk = !fOn || contRunMin >= MIN_RUN_M;

// === Analýza FVE plánu ===
var futureSolar = 0;
for (var i = 1; i < plan.length; i++) {
    if (plan[i].isSolarHour) futureSolar++;
}
var hasFutureSolar = futureSolar > 0 || solRemain >= SOLAR_OK;

// === Výpočty ===
// Léto + bazén ≤ 10°C → žádné minimum (0), jen solar surplus
var minReq = letni ? (poolT > T_MIN ? MIN_S : 0) : MIN_W;
var rem = Math.max(0, minReq - run);
var met = rem <= 0;
var minToDead = Math.max(0, (DEAD * 60) - nowM);
var urgent = !met && minReq > 0 && minToDead <= (rem + 15);

// Podmínky
var gSurp = surplus >= S_ON;
var oSurp = surplus >= S_OFF;
var inSetrit = mode === "setrit";
var inNormal = mode === "normal";
var lowSOC = soc < SOC_LOW;

// Anti-cycling
var lastOn = flow.get("filt_on_ts") || 0;
var lastOff = flow.get("filt_off_ts") || 0;

// === ROZHODOVÁNÍ ===
var act = "none", rsn = "";

if (!fOn) {
    // 0a. Teplota bazénu < T_FREEZE → filtrace NESMÍ běžet (zákon 10.1)
    if (poolT < T_FREEZE && poolT > 0) {
        node.status({fill: "blue", shape: "ring", text: "Pool " + poolT + "°C < " + T_FREEZE + "°C → freeze lock"});
        return [null, null, null, null];
    }
    // 0. NIBE kompresor aktivní → nepouštět filtraci (NIBE má vyšší prioritu)
    if (nibeComp) {
        node.status({fill: "grey", shape: "ring", text: "NIBE komp. běží → pauza " + run + "/" + minReq + "m"});
        return [null, null, null, null];
    }
    // 1. Solární přebytek → ON (zdarma)
    if (gSurp && !met) {
        act = "on";
        rsn = "Solar +" + Math.round(surplus) + "W";
    }
    // 2. Nesplněno min + ŠETŘIT + žádný budoucí solar → ON
    else if (!met && minReq > 0 && inSetrit && !hasFutureSolar) {
        act = "on";
        rsn = "Šetřit L" + pLvl + ", žádný solar, zbývá " + rem + "min";
    }
    // 3. URGENT + ŠETŘIT → ON
    else if (urgent && inSetrit) {
        act = "on";
        rsn = "Deadline! " + rem + "min do " + DEAD + ":00 (šetřit)";
    }
    // 4. URGENT + NORMAL + SOC OK → ON
    else if (urgent && inNormal && !lowSOC) {
        act = "on";
        rsn = "Deadline! " + rem + "min (normal, SOC " + soc + "%)";
    }
    // 5. SUPER URGENT (< 20 min do deadline) → ON za každou cenu
    else if (!met && minReq > 0 && minToDead <= 20 && minToDead > 0) {
        act = "on";
        rsn = "EMERGENCY! " + minToDead + "min do deadline";
    }

    // Anti-cycling
    if (act === "on" && (now - lastOff) < ANTI) {
        act = "none"; rsn = "";
    }

} else {
    // --- BĚŽÍ ---
    // 0a. Pool freeze → OFF
    if (poolT < T_FREEZE && poolT > 0) {
        act = "off"; rsn = "Pool " + poolT + "°C < " + T_FREEZE + "°C";
    }
    // 0. NIBE kompresor aktivní → vypnout filtraci (NIBE má vyšší prioritu)
    if (nibeComp) {
        act = "off"; rsn = "NIBE komp. běží";
    }
    // Žádný hard cutoff — filtrace může běžet přes deadline pokud plní minimum

    // 1. Minimum splněno → OFF (zákon 10.1: nesmí běžet déle než požadováno)
    if (met) {
        act = "off";
        rsn = "OK " + run + "/" + minReq + "min";
    }
    // 2. NORMAL mód + nízký SOC + žádný přebytek → OFF (ochrana baterie)
    else if (!oSurp && inNormal && lowSOC) {
        act = "off";
        rsn = "Ochrana bat! SOC:" + soc + "%, mode:" + mode;
    }
    // 3. Min nesplněno + přebytek klesl + budoucí solar → PAUZA
    else if (!met && minReq > 0 && !oSurp && hasFutureSolar && !urgent) {
        act = "off";
        rsn = "Pauza → čeká solar (" + solRemain.toFixed(0) + "kWh rem)";
    }
    // 4. Min nesplněno + přebytek klesl + není šetřit + není urgent → PAUZA
    else if (!met && minReq > 0 && !oSurp && !inSetrit && !urgent) {
        act = "off";
        rsn = "Pauza (normal mód, SOC:" + soc + "%)";
    }
    // Pokud minReq=0 (léto+studený bazén) a žádný přebytek → OFF
    else if (minReq === 0 && !oSurp) {
        act = "off";
        rsn = "Bez minima, přebytek " + Math.round(surplus) + "W";
    }

    // Min continuous run protection (zákon 10.1: nepřerušovat pokud < MIN_RUN_M min)
    if (act === "off" && !minRunOk && !met && poolT >= T_FREEZE) {
        act = "none"; rsn = "";
    }
    // Anti-cycling (bez výjimek — žádný hard cutoff)
    if (act === "off" && (now - lastOn) < ANTI && !nibeComp && !met) {
        act = "none"; rsn = "";
    }
}

// Track transitions
if (act === "on") flow.set("filt_on_ts", now);
if (act === "off") flow.set("filt_off_ts", now);

// === Status ===
var st = (letni ? "L" : "Z") + (fOn ? "•ON" : "•OFF");
st += " " + run + "/" + minReq + "m";
st += " ΔP:" + Math.round(surplus) + "W";
st += " SOC:" + soc + "% " + mode + "/L" + pLvl;
st += " T:" + poolT + "°C";
if (fOn) st += " CR:" + contRunMin.toFixed(0) + "/" + MIN_RUN_M + "m";
if (hasFutureSolar) st += " ☀" + solRemain.toFixed(0) + "kWh";
if (act !== "none") st += " → " + act + ": " + rsn;
var cl = act === "on" ? "blue" : act === "off" ? "yellow" : "green";
node.status({fill: cl, shape: "dot", text: st});

// === Výstupy [0]=ON, [1]=OFF, [2]=flag_on, [3]=flag_off ===
var out = [null, null, null, null];
if (act === "on") out[0] = {payload: "on", reason: rsn};
if (act === "off") out[1] = {payload: "off", reason: rsn};
if (act === "on" && gSurp) out[2] = {payload: "on"};
if (newDay) out[3] = {payload: "off"};

// Export status pro dashboard
global.set("filtrace_status", {run: run, minReq: minReq, met: met, remaining: Math.max(0, minReq - run)});

return out;

// =============================================================================
// FVE Konfigurace — čtení z HA entit + výchozí hodnoty
// =============================================================================

// Pomocné funkce pro čtení z HA
function getHAFloat(entityId, fallback) {
    var e = global.get("homeassistant.homeAssistant.states['" + entityId + "']") || {};
    var v = parseFloat(e.state);
    return isNaN(v) ? fallback : v;
}
function getHABool(entityId, fallback) {
    var e = global.get("homeassistant.homeAssistant.states['" + entityId + "']") || {};
    if (e.state === "on") return true;
    if (e.state === "off") return false;
    return fallback;
}

const config = {
    // =====================================================================
    // BATERIE — kapacita a amortizace čteny z HA (input_number)
    // =====================================================================
    kapacita_baterie_kwh: getHAFloat("input_number.fve_kapacita_baterie", 28),
    min_soc: 20,
    max_daily_soc: 80,
    amortizace_baterie_czk_kwh: getHAFloat("input_number.fve_amortizace_baterie", 1.5),
    charge_efficiency: 0.90,           // 10% ztráta při nabíjení
    discharge_efficiency: 0.90,        // 10% ztráta při vybíjení
    charge_rate_kwh: 5,                // rychlost nabíjení ze sítě (kWh/h)
    soc_drop_normal_pct: 5,            // % pokles SOC za hodinu v NORMAL módu
    daily_consumption_kwh: 20,         // odhadovaná denní spotřeba domu (kWh)
    soc_drop_setrit_pct: 1,

    // =====================================================================
    // SÍŤ — limity čteny z HA (input_number)
    // =====================================================================
    max_feed_in_w: getHAFloat("input_number.fve_max_feed_in", 7600),
    max_spotreba_sit_w: getHAFloat("input_number.fve_max_spotreba_sit", 22000),
    safety_margin_w: 2000,
    charger_max_amper: 16,             // max ampéry wallboxu
    charger_faze: 3,                   // počet fází wallboxu
    sit_napeti: 230,                   // napětí sítě (V)
    jistic_a: getHAFloat("input_number.fve_jistic", 32),

    // =====================================================================
    // NABÍJENÍ AUTA
    // =====================================================================
    nabijeni_auta_forecast_kwh: 40,    // min forecast výroby (kWh) pro letní solární nabíjení
    nabijeni_auta_min_soc: 95,         // min SOC baterie pro nabíjení ze sítě (%)
    nabijeni_auta_solar_w: 4000,       // min přebytek výroby pro sluneční nabíjení (W)
    nabijeni_auta_cena_prah_vyssi: 4.3,// max cena kWh pro nabíjení ze sítě (Kč) - vyšší práh
    nabijeni_auta_cena_prah_nizsi: 3.0,// max cena kWh pro nabíjení ze sítě (Kč) - nižší práh
    nabijeni_auta_min_soc_slunce: 85,  // min SOC baterie pro povolení solárního nabíjení (%)
    nabijeni_auta_pretizeni_w: 18000,  // práh přetížení sítě při nabíjení auta (W)
    nabijeni_auta_soc_drain_prah: 95,  // SOC práh pro drain mód solárního nabíjení (%)
    nabijeni_auta_soc_drain_w: 1000,   // max odběr z baterie v drain módu při SOC>=95% (W)
    nabijeni_auta_soc_charge_w: 1000,  // rezerva solaru pro nabíjení baterie při SOC<95% (W)
    nabijeni_auta_target_batt_w: 1000, // cíl nabíjení baterie při sol. nabíjení (W)
    nabijeni_auta_dead_band_w: 500,    // dead band korekce ±W

    // =====================================================================
    // FVE INSTALACE
    // =====================================================================
    fve_peak_kwp: 3,
    fve_azimut: 270,
    fve_sklon: 50,

    // =====================================================================
    // VICTRON MQTT
    // =====================================================================
    victron_id: "c0619ab69c71",
    victron_mqtt_prefix: "victron",

    // =====================================================================
    // SOLÁRNÍ PŘEDPOVĚĎ
    // =====================================================================
    solar_forecast_source: "VICTRON",  // "VICTRON" nebo "OPEN_METEO"

    // =====================================================================
    // CENOVÉ PRAHY
    // =====================================================================
    prah_levna_energie: 4,             // level <= prah = levná energie
    prah_draha_energie: 12,            // level >= prah = drahá energie
    prah_ultra_levna_nakup: 1.0,       // nákupní cena (Kč/kWh) pod kterou platí ultra-levný režim

    // =====================================================================
    // *** NOČNÍ REŽIM (22:00 – 04:00) ***
    // =====================================================================
    topeni_nocni_snizeni: 0.5,         // noční snížení cílové teploty (°C) — platí i pro vysoký solární den
    topeni_nocni_od: 22,               // začátek nočního režimu (hodina)
    topeni_nocni_do: 4,                // konec nočního režimu (hodina)
    topeni_nouzova_teplota: 18,        // nouzová teplota — topit i v drahých hodinách (°C)

    // =====================================================================
    // *** TOPENÍ DOMU — HYSTEREZE A PRAHY ***
    // topeni_min/max_teplota_nadrze se čtou přímo z HA (input_number)
    // topeni_max_teplota_patron se čte z HA (input_number)
    // =====================================================================
    topeni_bezpecny_pokles: 0.7,       // bezpečný pokles pod target (°C)
    topeni_hystereze_chlazeni: 1.0,    // hystereze chlazení nad target (°C)
