            return { mode: M.PRODAVAT, reason: "Prodej do sítě (zisk " + Math.round((zisk - naklady) * 10) / 10 + " Kč/kWh), SOC " + S + "% (cíl " + x.sellTarget + "%)" };
    }

    // Ochrana min SOC (mimo solární hodiny)
    if (soc <= C.minSoc && !x.sO[offset]) return { mode: M.SETRIT, reason: "Ochrana minimální SOC, SOC " + S + "% ≤ " + C.minSoc + "%" };

    // Solární hodiny — logika dle § 4.9.2 + v25.15:
    //   1. Drahá hodina + SOC > minSoc → NORMAL (vybíjíme — vyhýbáme se drahé síti)
    //   2. Discharge hodina + záporný zisk + SOC > minSoc → NORMAL (v25.15 výjimka)
    //   3. Levná hodina → ŠETŘIT (§ 4.3 — šetříme za nejlevnějších podmínek)
    if (x.sO[offset]) {
        var ziskProc = solarniZiskProc(hodina, frac, level);
        var socPoSolaru = clamp(soc + ziskProc);
        var jeDraha = level >= C.DRAHA;

        // DRAHÁ hodina: vybíjíme baterii, solar pokrývá co může (v25.15 fix)
        // Ochrana: jen proti absolutnímu minimu (minSoc), ne minSoc+socN
        if (jeDraha && soc > C.minSoc) {
            return { mode: M.NORMAL, reason: "Solární + drahá hodina" + nibePopiska + ", SOC " + S + "→~" + socPoSolaru + "%" };
        }
        // Discharge hodina (arbitráž) se záporným ziskem: vybíjíme (v25.15 fix)
        if (ziskProc <= 0 && x.dO[offset] && soc > C.minSoc) {
            return { mode: M.NORMAL, reason: "Solární (nízký zisk) + vybíjení" + nibePopiska + ", SOC " + S + "→~" + socPoSolaru + "%" };
        }
        // §4.9: při vysoké denní predikci + dost SOC + zbývající solar vždy preferuj NORMAL
        var planAgg = (Math.max(x.fD || 0, liveForecastTodayKwh) > C.planAggSolarKwh) && (soc > C.planAggSoc) && (Math.max(x.rS || 0, liveRemainingSolarKwh) > C.planAggRemainKwh);
        if (!jeDraha && planAgg) {
            return { mode: M.NORMAL, reason: "Solární hodina (agresivní NORMAL)" + nibePopiska + ", SOC " + S + "→~" + socPoSolaru + "%" };
        }
        // Kladný solární zisk v levné hodině: solar nabíjí baterii, šetříme
        if (!jeDraha && ziskProc > 0) {
            return { mode: M.SETRIT, reason: "Solární hodina (levná cena, nabíjím ze slunce)" + nibePopiska + ", SOC " + S + "→~" + socPoSolaru + "%" };
        }
        // Drahá hodina ale SOC na absolutním minimu: nemůžeme vybíjet
        if (jeDraha) {
            return { mode: M.SETRIT, reason: "Solární + drahá hodina, ochrana min. SOC" + nibePopiska + ", SOC " + S + "%" };
        }
        // Fallback: levná hodina, šetříme baterii
        return { mode: M.SETRIT, reason: "Solární hodina, šetřím baterii" + nibePopiska + ", SOC " + S + "%" };
    }

    // Nesluneční hodiny — vybíjení nebo šetření
    var ztrataProc = spotrebovaZtrataProc(hodina, frac);
    if (x.dO[offset] && zaokrouhli(soc - ztrataProc) >= C.minSoc + C.socN) {
        var socPoVybijeni = clamp(soc - ztrataProc);
        var popis = level >= C.DRAHA ? "Drahá hodina" : "Střední cena";
        return { mode: M.NORMAL, reason: popis + ", SOC " + S + "→~" + socPoVybijeni + "%" };
    }
    if (level >= C.DRAHA && zaokrouhli(soc - ztrataProc) >= C.minSoc + C.socN) {
        var socDraha = clamp(soc - ztrataProc);
        return { mode: M.NORMAL, reason: "Drahá hodina, SOC " + S + "→~" + socDraha + "%" };
    }
    if (x.aS[offset]) return { mode: M.SETRIT, reason: "Šetřím pro dražší hodiny, SOC " + S + "%" };
    return { mode: M.SETRIT, reason: "Šetřím baterii, SOC " + S + "%" };
}

