// Grid Lost ochrana — při výpadku sítě nenabíjet auto ze sítě
var gridLostState = global.get("homeassistant.homeAssistant.states['sensor.grid_lost_ciselny']") || {};
var gridLost = parseInt(gridLostState.state || "0") >= 2;
if (gridLost) {
    msg.payload = 0;
    node.status({fill:"red", shape:"dot", text:"⚡GRID LOST — nabíjení auta BLOKOVÁNO"});
    return msg;
}
const MAX_GRID = config.max_spotreba_sit_w || 22000;
const SAFETY_MARGIN = config.safety_margin_w || 2000;
const SAFE_LIMIT = MAX_GRID - SAFETY_MARGIN;

const spotreba = msg.payload_spotreba || 0;
const charger_amps = msg.payload_charger || 0;

// Přičti výkon nabíjení baterie pokud se baterie nabíjí
const arbiter = global.get("energy_arbiter") || {};
const batteryChargeW = arbiter.battery_charging ? (config.charge_rate_kwh || 5) * 1000 : 0;

let headroom = SAFE_LIMIT - spotreba - batteryChargeW;
const NAPETI = config.sit_napeti || 230;
const FAZE = config.charger_faze || 3;
const MAX_AMP = config.charger_max_amper || 16;
let max_amper = Math.floor(headroom / NAPETI / FAZE + charger_amps);

if (max_amper > MAX_AMP) {
    max_amper = MAX_AMP;
} else if (max_amper < 6) {
    max_amper = 0;
}

msg.payload = max_amper;

node.status({
    fill: max_amper > 0 ? "green" : "red",
    shape: "dot",
    text: max_amper + "A | spotreba:" + Math.round(spotreba) +
            " bat:" + batteryChargeW +
            " limit:" + SAFE_LIMIT + " headroom:" + Math.round(headroom)
});

return msg;

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_cena_prah_nizsi || 3.0;
var stav = global.get("homeassistant.homeAssistant.states['input_number.aktualni_cena_kwh']") || {};
var cena = parseFloat(stav.state);
if (isNaN(cena)) { node.status({fill:'red',shape:'ring',text:'cena NaN'}); return [null, msg]; }
node.status({fill: cena <= prah ? 'green' : 'yellow', shape:'dot', text: cena + ' Kc (prah ' + prah + ')'});
if (cena <= prah) { return [msg, null]; }
return [null, msg];

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_cena_prah_vyssi || 4.3;
var stav = global.get("homeassistant.homeAssistant.states['input_number.aktualni_cena_kwh']") || {};
var cena = parseFloat(stav.state);
if (isNaN(cena)) { node.status({fill:'red',shape:'ring',text:'cena NaN'}); return [null, msg]; }
node.status({fill: cena <= prah ? 'green' : 'yellow', shape:'dot', text: cena + ' Kc (prah ' + prah + ')'});
if (cena <= prah) { return [msg, null]; }
return [null, msg];

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_pretizeni_w || 18000;
var spotreba = parseFloat(msg.payload);
if (isNaN(spotreba)) { return [null, null]; }
node.status({fill: spotreba > prah ? 'red' : 'green', shape:'dot', text: Math.round(spotreba) + 'W (prah ' + prah + 'W)'});
if (spotreba > prah) { return [msg, null]; }
return [null, msg];

var config = global.get('fve_config') || {};
var prah = config.nabijeni_auta_min_soc_slunce || 85;
var stav = global.get("homeassistant.homeAssistant.states['sensor.battery_percent']") || {};
var soc = parseFloat(stav.state);
if (isNaN(soc)) { node.status({fill:'red',shape:'ring',text:'SOC NaN'}); return [null, msg]; }
node.status({fill: soc > prah ? 'green' : 'yellow', shape:'dot', text: soc + '% (prah ' + prah + '%)'});
if (soc > prah) { return [msg, null]; }
return [null, msg];

// Korekční smyčka nabíjení auta ze slunce v5 — per laws 5.0, 5.1
var spotrSit=msg.payload_spotreba||0,soc=msg.payload_battpct;
var cfg=global.get("fve_config")||{};

// Cooldown (prevents overlapping chain)
var now=Date.now(),lastRun=global.get("solar_corr_last_run")||0;
if(now-lastRun<4000)return null;
global.set("solar_corr_last_run",now);

// LAW 5.0: Automation OFF → do NOTHING
var autoS=global.get("homeassistant.homeAssistant.states['input_boolean.automatizovat_nabijeni_auta']")||{};
if(autoS.state!=="on"){node.status({fill:"grey",shape:"ring",text:"Auto OFF"});return null;}

// Config
var MSS=cfg.nabijeni_auta_min_soc_slunce||85;
var SDT=cfg.nabijeni_auta_soc_drain_prah||95;
var SDW=cfg.nabijeni_auta_soc_drain_w||1500;
var GRID_MAX=cfg.nabijeni_auta_max_grid_w||200;
var BR=cfg.balancing_grid_reserve_w||1000;
var MAX_START=cfg.nabijeni_auta_max_start_a||8;

// Read states
var aS=global.get("homeassistant.homeAssistant.states['select.wallboxu_garaz_amperace']")||{};
var curA=parseInt(String(aS.state||"0").replace(/[^0-9]/g,""),10)||0;
var bMinus=msg.payload_batt_minus||0,rozW=msg.payload;
var bS=global.get("homeassistant.homeAssistant.states['sensor.nabijeni_baterii']")||{};
var bW=parseFloat(bS.state)||0;
var gImp=global.get("homeassistant.homeAssistant.states['sensor.fve_celkovy_odber_ze_site']")||{};
var gGen=global.get("homeassistant.homeAssistant.states['sensor.spotreba_ze_site']")||{};
var gridW=parseFloat(gImp.state); if(isNaN(gridW)) gridW=parseFloat(gGen.state)||0;
var wbS=global.get("homeassistant.homeAssistant.states['switch.wallbox_garaz_start_stop']")||{};
var wbOn=wbS.state==="on";

// LAW 5.1: SOC < MSS → stop (0A)
if(soc<MSS){node.status({fill:"red",shape:"ring",text:"SOC "+soc+"%<"+MSS+"%→0A"});msg.payload=0;return msg;}

var hi=soc>=99;
var drain=soc>=SDT;
var gMax=GRID_MAX;

// === CHARGER RUNNING (curA >= 6) — feedback ±1A per cycle (law 5.1) ===
if(curA>=6&&wbOn){
  var tA=curA,zone="";
  // HIGHEST PRIORITY: grid draw > threshold — immediate low-amp stop guard
  if(gridW>gMax && curA<=6){
    var lowCnt=(global.get("solar_corr_low6_cnt")||0)+1;global.set("solar_corr_low6_cnt",lowCnt);
    if(lowCnt>=3){tA=0;global.set("solar_corr_low6_cnt",0);zone="GRID_STOP:"+Math.round(gridW)+"W>"+gMax+"W";}
    else{tA=6;zone="GRID_6A:"+Math.round(gridW)+"W c"+lowCnt;}
    global.set("solar_corr_ghc",0);
  }
  else if(gridW>gMax){
    global.set("solar_corr_low6_cnt",0);
    var ghc=(global.get("solar_corr_ghc")||0)+1;global.set("solar_corr_ghc",ghc);
    if(ghc>=2){tA=curA-1;global.set("solar_corr_ghc",0);zone="GRID:"+Math.round(gridW)+"W>"+gMax+"W";}
    else{zone="GW:"+Math.round(gridW)+"W(wait)";}
  }
  // DRAIN (SOC>=95%): battery MUST discharge
  else if(drain){
    global.set("solar_corr_ghc",0);zone="DRAIN";
    var MAX_DR=cfg.nabijeni_auta_max_drain_w||2500;
    if(bW>300)tA=curA+1;
    else if(bW<-MAX_DR)tA=curA-1;
  }
  // CHRG (SOC 85-95%): battery must charge ~1kW
  else{
    global.set("solar_corr_ghc",0);zone="CHRG";
    var MAX_CHR=cfg.nabijeni_auta_max_charge_w||1000;
    if(bW<0)tA=curA-1;
    else if(bW>MAX_CHR&&gridW<gMax)tA=curA+1;
  }
  // Clamp: 6-16A — hold 6A for 3 cycles before stop (transient resilience)
  if(tA<6){
    if(zone.indexOf("GRID_STOP:")===0){
      tA=0;global.set("solar_corr_stop_cnt",0);
    } else {
      var sc=(global.get("solar_corr_stop_cnt")||0)+1;
      if(sc>=3){tA=0;global.set("solar_corr_stop_cnt",0);}
      else{tA=6;global.set("solar_corr_stop_cnt",sc);}
    }
  }else{global.set("solar_corr_stop_cnt",0);}
  if(tA>16)tA=16;
  node.status({fill:tA>0?"green":"red",shape:"dot",
    text:tA+"A("+zone+" b:"+Math.round(bW)+"W g:"+Math.round(gridW)+"W n:"+curA+"A SOC:"+soc+"%)"});
  msg.payload=tA;return msg;
}

// === STARTUP — conservative: cap at MAX_START (default 8A), feedback increases ===
var curW=curA*3*230;
var avW=rozW+curW+Math.max(0,bW);
if(hi)avW-=BR;
else if(soc>=MSS&&!drain){
  var SCW=cfg.nabijeni_auta_soc_charge_w||1000;
  avW-=SCW;if(bMinus>50)avW-=bMinus;
}else if(drain)avW+=SDW;

var tA2=Math.floor(avW/690);
if(tA2>MAX_START)tA2=MAX_START;
if(tA2<6)tA2=0;
node.status({fill:tA2>0?"green":"red",shape:"dot",
  text:tA2+"A(START av:"+Math.round(avW)+"W g:"+Math.round(gridW)+"W SOC:"+soc+"%)"});
msg.payload=tA2;return msg;

// Čtení aktuálních cen z globální proměnné (bez dotazu do DB)
const prices = global.get("fve_prices_forecast") || [];
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();

let minuteStart = 0;
if (minute >= 0 && minute < 15) minuteStart = 0;
else if (minute >= 15 && minute < 30) minuteStart = 15;
else if (minute >= 30 && minute < 45) minuteStart = 30;
else minuteStart = 45;

// Find current row
let currentRow = null;
for (const row of prices) {
    if (row.day === "hoursToday" && row.hour === hour && row.minute >= minuteStart && row.minute < minuteStart + 15) {
        currentRow = row;
        break;
    }
}
// Fallback: match just by hour
if (!currentRow) {
    for (const row of prices) {
        if (row.hour === hour) {
            currentRow = row;
            break;
        }
    }
}

if (!currentRow) {
    node.status({fill: "red", shape: "dot", text: "Žádná data pro " + hour + "h"});
    return null;
}

// Find cheapest hours for today
const todayPrices = prices.filter(r => r.day === "hoursToday" || r.day === (currentRow ? currentRow.day : ""));
const hourMap = {};
for (const r of todayPrices) {
    if (!hourMap[r.hour] || r.priceCZKhourBuy < hourMap[r.hour]) {
        hourMap[r.hour] = r.priceCZKhourBuy;
    }
}
const sorted = Object.entries(hourMap).sort((a, b) => a[1] - b[1]);
const cheapestHourBuy = sorted.length > 0 ? parseInt(sorted[0][0]) : 0;
const cheapestSecondHourBuy = sorted.length > 1 ? parseInt(sorted[1][0]) : 0;

const result = {
    priceCZKhourBuy: currentRow.priceCZKhourBuy,
    priceCZKquarterBuy: currentRow.priceCZKquarterBuy,
    priceCZKhourProd: currentRow.priceCZKhourProd,
    priceCZKquarterProd: currentRow.priceCZKquarterProd,
    levelCheapestHourBuy: currentRow.levelCheapestHourBuy,
    levelCheapestQuarterBuy: currentRow.levelCheapestQuarterBuy,
    levelMostExpensiveHourProd: currentRow.levelMostExpensiveHourProd,
    levelMostExpensiveQuarterProd: currentRow.levelMostExpensiveQuarterProd,
    isCheapestHourBuy: currentRow.levelCheapestHourBuy === 1 ? 1 : 0,
    isCheapestSecondHourBuy: currentRow.levelCheapestHourBuy === 2 ? 1 : 0,
    isMostExpensiveHourProd: currentRow.levelMostExpensiveHourProd === 1 ? 1 : 0,
    isMostExpensiveSecondHourProd: currentRow.levelMostExpensiveHourProd === 2 ? 1 : 0,
    isCheapestQuarterBuy: currentRow.levelCheapestQuarterBuy === 1 ? 1 : 0,
    isCheapestSecondQuarterBuy: currentRow.levelCheapestQuarterBuy === 2 ? 1 : 0,
    isMostExpensiveQuarterProd: currentRow.levelMostExpensiveQuarterProd === 1 ? 1 : 0,
    isMostExpensiveSecondQuarterProd: currentRow.levelMostExpensiveQuarterProd === 2 ? 1 : 0,
    cheapestHourBuy: cheapestHourBuy,
    cheapestSecondHourBuy: cheapestSecondHourBuy
};

msg.payload = [result];

// Also update global price level
global.set("fve_current_price", {
    buy: result.priceCZKhourBuy,
    sell: result.priceCZKhourProd,
    levelBuy: result.levelCheapestHourBuy,
    levelSell: result.levelMostExpensiveHourProd
});
global.set("fve_price_level", result.levelCheapestHourBuy);

node.status({fill: result.levelCheapestHourBuy <= 4 ? "green" : (result.levelCheapestHourBuy >= 7 ? "red" : "yellow"), shape: "dot", text: "Level " + result.levelCheapestHourBuy + " @ " + hour + "h | " + prices.length + " rows"});
return msg;

let d = new Date()
let current_minute = d.getMinutes()
let current_hour = d.getHours()
let spusteno_minutou = flow.get("spusteno_minutou")

if ([0, 15, 30, 45].includes(current_minute) && spusteno_minutou != current_minute) {
    flow.set("spusteno_minutou", current_minute)
    return msg;
}

let myCount = flow.get("myCount")
let count = msg.parts.count

if (myCount == count) {
  return msg;
} else flow.set("myCount", ++myCount)

flow.set("myCount", 1)
flow.set("myRecordCount", 0)

return msg;

let myCount = flow.get("myCount")
let myRecordCount = flow.get("myRecordCount")

if (myCount == myRecordCount) {
  msg.payload = "ahoj"
  return msg;
} else flow.set("myCount", ++myCount)

let myCount = flow.get("myCount")
let count = msg.parts.count

if (myCount == count) {
  return msg;
} else flow.set("myCount", ++myCount)

// Po výpočtu levelů: uložit všechny ceny do globální proměnné
const prices = msg.payload || [];
global.set("fve_prices_forecast", prices);

// Find and set current price
const now = new Date();
const hour = now.getHours();
let currentLevel = 5;
for (const row of prices) {
    if (row.hour === hour && row.day === "hoursToday") {
        currentLevel = row.levelCheapestHourBuy || 5;
        global.set("fve_current_price", {
            buy: row.priceCZKhourBuy,
            sell: row.priceCZKhourProd,
            levelBuy: row.levelCheapestHourBuy,
            levelSell: row.levelMostExpensiveHourProd
        });
        break;
    }
}
global.set("fve_price_level", currentLevel);
node.status({fill: "green", shape: "dot", text: prices.length + " cen uloženo do global"});
return msg;
